    #[tokio::test]
    async fn test_context_mode_returns_no_answer() {
        let dir = tempfile::tempdir().unwrap();
        let pipeline = setup_pipeline(dir.path(), false).await;

        let response = pipeline.context("what is entry 0?", "proj", None).await.unwrap();

        assert!(response.answer.is_none());
        assert!(!response.context.context.is_empty());
        assert!(response.context.metrics.sources_included > 0);
        assert!(response.trace.generation.is_none());
        assert!(response.trace.total_latency_ms < 5000);
        assert_eq!(response.trace.retrieval.retriever_name, "vector");
        assert_eq!(response.trace.augmentation.augmenter_name, "structured");
    }

